import '../lib/release_handle.dart';
import '../lib/release_manager.dart';
import '../lib/release_store.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final store = ReleaseStore()
    ..add('r1', {'version': 'one'})
    ..add('r2', {'version': 'two'})
    ..add('r3', {'version': 'three'});
  final manager = ReleaseManager(store)..activate('r1');
  final first = manager.openActive();
  final second = manager.openActive();

  manager.activate('r2');
  final middle = manager.openActive();
  manager.activate('r3');
  check(store.contains('r1') && store.contains('r2'),
      'each retired generation waits for its own readers');

  first.close();
  check(store.contains('r1'), 'one of two readers cannot retire the generation');
  first.close();
  check(store.contains('r1'), 'closing the same handle twice does not change accounting');

  middle.close();
  check(!store.contains('r2'), 'an independent retired generation is collected');
  check(store.contains('r1'), 'collecting one generation does not affect another');

  second.close();
  check(!store.contains('r1'), 'the final distinct reader releases the generation');
  check(store.contains('r3'), 'the active generation is never collected');

  final standalone = ReleaseHandle('local', {'version': 'local'});
  standalone.close();
  standalone.close();
  check(standalone.isClosed, 'repeated direct closure is harmless');
}
